searchBook.JSParser:
function functionName(config, params, result) {

    result = result. replace(/<meta[^>]*charset[^>]*>/gi, "");

    let list = []
    let xml = params.nativeTool.XPathParserWithSource(result)

    if (/search/.test(params.responseUrl)) {    //搜索页
        let items = xml.queryWithXPath(`//div[@id='sitembox']/dl`)

        for (i in items) {

        // params.nativeTool.log()
            let obj = {

                "bookName": items[i].queryWithXPath(`//dd/h3/a/text()`)[0].content(),
                "detailUrl": items[i].queryWithXPath(`//dd/h3/a/@href`)[0].content(),
                "author": items[i].queryWithXPath(`//dd[2]/span[1]/text()`)[0].content(),
                "desc": items[i].queryWithXPath(`//dd[3]/text()`)[0].content(),
                "cover": items[i].queryWithXPath(`//dt//img/@src`)[0].content(),
                "cat": items[i].queryWithXPath(`//dd[2]/span[3]/text()`)[0].content(),
                "status": items[i].queryWithXPath(`//dd[2]/span[2]/text()`)[0].content(),
                "wordCount": items[i].queryWithXPath(`//dd[2]/span[4]/text()`)[0].content(),
                "lastChapterTitle": items[i].queryWithXPath(`//dd[4]/a/text()`)[0].content()
            }


            list.push(obj)
        }
    } else {    //详情页
        // params.nativeTool.log()

        let detailObj = {
            "bookName": xml.queryWithXPath(`//div[@id='bookinfo']/div[2]/div[1]/h1/text()`)[0].content(),
            "author": xml.queryWithXPath(`//div[@id='bookinfo']/div[2]/div[1]//a/text()`)[0].content(),
            "cat": xml.queryWithXPath(`//div[@id='bookinfo']/div[2]/div[2]//li[1]/span/text()`)[0].content(),
            "detailUrl": params.responseUrl,
            "desc": xml.queryWithXPath(`//div[@id='bookinfo']/div[2]/div[3]/p/text()`)[0].content(),
            "cover": xml.queryWithXPath(`//div[@id='bookinfo']//img/@src`)[0].content(),
            "lastChapterTitle": xml.queryWithXPath(`//div[@id='newlist']//li[1]/a/text()`)[0].content(),
            "status": xml.queryWithXPath(`//div[@id='bookinfo']/div[2]/div[2]//li[2]/span/text()`)[0].content(),
            "wordCount": xml.queryWithXPath(`//div[@id='bookinfo']/div[2]/div[2]//li[4]/span/text()`)[0].content(),

        }

        list.push(detailObj)
    }

    return {
        "list": list
    }
}

